async (params, browser) => {
  // Open Last.fm search
  await browser.open(`https://www.last.fm/search?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('.grid-items-item-details, .chartlist-row, .page-content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const artists = []; document.querySelectorAll('.grid-items-item-details').forEach((el, i) => { if (i < 10) { const nameEl = el.querySelector('.grid-items-item-main-text a.link-block-target'); const auxEl = el.querySelector('.grid-items-item-aux-text'); artists.push({ name: nameEl?.textContent?.trim() || '', url: nameEl?.href || '', listeners: auxEl?.textContent?.trim() || '' }); } }); const tracks = []; document.querySelectorAll('.chartlist-row').forEach((el, i) => { if (i < 10) { const nameEl = el.querySelector('.chartlist-name a.link-block-target'); const artistEl = el.querySelector('.chartlist-artist a'); const countEl = el.querySelector('.chartlist-count-bar-value'); tracks.push({ name: nameEl?.textContent?.trim() || '', url: nameEl?.href || '', artist: artistEl?.textContent?.trim() || '', plays: countEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', artist_count: artists.length, artists, track_count: tracks.length, tracks };`)

  return search_results
}
